# Improved border detection with iterative approach
def detect_borders(g):
    H, W = len(g), len(g[0])

    from collections import Counter
    all_colors = Counter()
    for r in range(H):
        for c in range(W):
            all_colors[g[r][c]] += 1
    bg = all_colors.most_common(1)[0][0]

    border_rows = set()
    border_row_colors = {}
    border_cols = set()
    border_col_colors = {}

    changed = True
    while changed:
        changed = False

        # Check rows (excluding border cols)
        non_bc = [c for c in range(W) if c not in border_cols]
        for r in range(H):
            if r in border_rows:
                continue
            vals = set(g[r][c] for c in non_bc)
            if len(vals) == 1 and g[r][non_bc[0]] != bg:
                border_rows.add(r)
                border_row_colors[r] = g[r][non_bc[0]]
                changed = True

        # Check cols (excluding border rows)
        non_br = [r for r in range(H) if r not in border_rows]
        for c in range(W):
            if c in border_cols:
                continue
            vals = set(g[r][c] for r in non_br)
            if len(vals) == 1 and g[non_br[0]][c] != bg:
                border_cols.add(c)
                border_col_colors[c] = g[non_br[0]][c]
                changed = True

    return bg, border_rows, border_row_colors, border_cols, border_col_colors

# Test on all examples
for label, samples in [("Train", train_samples), ("Test", test_samples)]:
    for i, s in enumerate(samples):
        g = s['input']
        bg, br, brc, bc, bcc = detect_borders(g)
        print(f"\n{label} {i}: bg={bg}")

        # Group strips
        def group_consecutive(s):
            s = sorted(s)
            groups = []
            for x in s:
                if groups and x == groups[-1][-1] + 1:
                    groups[-1].append(x)
                else:
                    groups.append([x])
            return groups

        h_strips = group_consecutive(br)
        v_strips = group_consecutive(bc)
        h_info = [(strip, brc[strip[0]]) for strip in h_strips]
        v_info = [(strip, bcc[strip[0]]) for strip in v_strips]
        print(f"  H strips: {[(s, c) for s, c in h_info]}")
        print(f"  V strips: {[(s, c) for s, c in v_info]}")

